<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/config/runtime.php';sds_session_start();define('SDS_PERPUSTAKAAN_APP',true);$root=dirname(__DIR__,2);require_once $root.'/db.php';require_once $root.'/config/perpus.php';try{sds_perpus_ensure_schema($conn);sds_perpus_expire_reservations($conn,100);}catch(Throwable $e){error_log('[OPAC akun startup] '.$e->getMessage());}
function ah($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}function member_csrf():string{if(empty($_SESSION['perpus_member_csrf']))$_SESSION['perpus_member_csrf']=bin2hex(random_bytes(24));return (string)$_SESSION['perpus_member_csrf'];}function check_member_csrf():void{$a=(string)($_SESSION['perpus_member_csrf']??'');$b=(string)($_POST['csrf']??'');if($a===''||$b===''||!hash_equals($a,$b))throw new RuntimeException('Sesi formulir berakhir. Muat ulang halaman.');}
$school=['nama_sekolah'=>'Sekolah','logo'=>''];$r=$conn->query('SELECT nama_sekolah,logo FROM pengaturan LIMIT 1');if($r&&($x=$r->fetch_assoc()))$school=array_merge($school,$x);$base=sds_base_url('perpustakaan/opac/');$error='';$message='';$requestedBook=max(0,(int)($_GET['reservasi']??$_SESSION['perpus_pending_reservation']??0));if($requestedBook>0)$_SESSION['perpus_pending_reservation']=$requestedBook;
if(isset($_GET['logout'])){unset($_SESSION['perpus_member_id'],$_SESSION['perpus_pending_reservation']);header('Location: '.$base.'akun.php');exit;}
if(($_SERVER['REQUEST_METHOD']??'')==='POST'&&($_POST['action']??'login')==='login'){$uid=trim((string)($_POST['rfid']??''));if($uid==='')$error='Tempelkan Kartu Pelajar Anda.';else{$stmt=$conn->prepare("SELECT a.id FROM perpus_anggota a JOIN kartu_rfid k ON k.pemilik_tipe=a.pemilik_tipe AND k.pemilik_id=a.pemilik_id WHERE k.uid=? AND a.status_keanggotaan='aktif' LIMIT 1");$stmt->bind_param('s',$uid);$stmt->execute();$mid=(int)($stmt->get_result()->fetch_assoc()['id']??0);$stmt->close();if($mid>0){session_regenerate_id(true);$_SESSION['perpus_member_id']=$mid;header('Location: '.$base.'akun.php'.($requestedBook>0?'?reservasi='.$requestedBook:''));exit;}else$error='Kartu pelajar tidak ditemukan atau keanggotaan tidak aktif.';}}
$mid=(int)($_SESSION['perpus_member_id']??0);
if($mid>0&&($_SERVER['REQUEST_METHOD']??'')==='POST'&&($_POST['action']??'')!=='login'){try{check_member_csrf();$action=(string)$_POST['action'];if($action==='reserve'){$bookId=(int)($_POST['book_id']??0);if(sds_perpus_setting_value($conn,'reservasi_aktif','1')!=='1')throw new RuntimeException('Reservasi sedang dinonaktifkan.');if($bookId<=0)throw new RuntimeException('Koleksi tidak valid.');$stmt=$conn->prepare('SELECT judul,status_opac FROM perpus_buku WHERE id=? LIMIT 1');$stmt->bind_param('i',$bookId);$stmt->execute();$book=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$book||!(int)$book['status_opac'])throw new RuntimeException('Koleksi tidak ditemukan pada OPAC.');$max=max(1,(int)sds_perpus_setting_value($conn,'reservasi_maks_per_anggota','3'));$stmt=$conn->prepare("SELECT COUNT(*) total FROM perpus_reservasi WHERE anggota_id=? AND status IN ('menunggu','siap')");$stmt->bind_param('i',$mid);$stmt->execute();$active=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();if($active>=$max)throw new RuntimeException('Batas reservasi aktif Anda sudah tercapai ('.$max.').');$stmt=$conn->prepare("SELECT id FROM perpus_reservasi WHERE anggota_id=? AND buku_id=? AND status IN ('menunggu','siap') LIMIT 1");$stmt->bind_param('ii',$mid,$bookId);$stmt->execute();$dup=$stmt->get_result()->fetch_assoc();$stmt->close();if($dup)throw new RuntimeException('Koleksi ini sudah berada dalam daftar reservasi Anda.');$stmt=$conn->prepare("SELECT d.id FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE p.anggota_id=? AND d.buku_id=? AND d.status='dipinjam' LIMIT 1");$stmt->bind_param('ii',$mid,$bookId);$stmt->execute();$borrowed=$stmt->get_result()->fetch_assoc();$stmt->close();if($borrowed)throw new RuntimeException('Koleksi ini sedang Anda pinjam.');$available=sds_perpus_reservation_available_count($conn,$bookId);$stmt=$conn->prepare("SELECT COUNT(*) total FROM perpus_reservasi WHERE buku_id=? AND status IN ('menunggu','siap')");$stmt->bind_param('i',$bookId);$stmt->execute();$queue=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();$status=($available>$queue)?'siap':'menunggu';$deadline=null;if($status==='siap'){$days=max(1,(int)sds_perpus_setting_value($conn,'reservasi_hari_ambil','2'));$deadline=(new DateTimeImmutable())->modify('+'.$days.' days')->format('Y-m-d H:i:s');}$stmt=$conn->prepare("INSERT INTO perpus_reservasi (anggota_id,buku_id,status,tanggal_siap,batas_ambil,sumber) VALUES (?,?,?,CASE WHEN ?='siap' THEN NOW() ELSE NULL END,?,'opac')");$stmt->bind_param('iisss',$mid,$bookId,$status,$status,$deadline);$stmt->execute();$rid=(int)$conn->insert_id;$stmt->close();if($status==='siap')sds_perpus_notify_member($conn,$mid,'reservasi_siap','Reservasi siap diambil','Koleksi “'.$book['judul'].'” tersedia dan dapat diambil sebelum '.date('d/m/Y H:i',strtotime((string)$deadline)).'.','reservasi',$rid);else sds_perpus_notify_member($conn,$mid,'reservasi_menunggu','Reservasi masuk antrean','Anda masuk antrean untuk koleksi “'.$book['judul'].'”.','reservasi',$rid);unset($_SESSION['perpus_pending_reservation']);$message=$status==='siap'?'Reservasi berhasil dan koleksi siap diambil.':'Reservasi berhasil. Anda masuk daftar antrean.';}elseif($action==='cancel_reservation'){$rid=(int)($_POST['reservation_id']??0);$stmt=$conn->prepare("SELECT buku_id FROM perpus_reservasi WHERE id=? AND anggota_id=? AND status IN ('menunggu','siap') LIMIT 1");$stmt->bind_param('ii',$rid,$mid);$stmt->execute();$bookId=(int)($stmt->get_result()->fetch_assoc()['buku_id']??0);$stmt->close();if($bookId<=0)throw new RuntimeException('Reservasi tidak dapat dibatalkan.');$stmt=$conn->prepare("UPDATE perpus_reservasi SET status='dibatalkan',tanggal_selesai=NOW() WHERE id=? AND anggota_id=? AND status IN ('menunggu','siap')");$stmt->bind_param('ii',$rid,$mid);$stmt->execute();$affected=$stmt->affected_rows;$stmt->close();if($affected<=0)throw new RuntimeException('Reservasi tidak dapat dibatalkan.');sds_perpus_promote_next_reservation($conn,$bookId,0);$message='Reservasi berhasil dibatalkan.';}elseif($action==='read_notifications'){$stmt=$conn->prepare("UPDATE perpus_notifikasi SET status='dibaca',dibaca_at=COALESCE(dibaca_at,NOW()) WHERE anggota_id=? AND status='baru'");$stmt->bind_param('i',$mid);$stmt->execute();$stmt->close();$message='Semua notifikasi ditandai sudah dibaca.';}else throw new RuntimeException('Aksi tidak dikenali.');}catch(Throwable $e){$error=$e->getMessage();}}
$member=null;$profile=null;$loans=[];$history=[];$reservations=[];$notifications=[];$fine=0;if($mid>0){$stmt=$conn->prepare('SELECT a.*,tm.nama tipe_member,tm.jumlah_peminjaman,tm.periode_peminjaman FROM perpus_anggota a LEFT JOIN perpus_tipe_member tm ON tm.id=a.tipe_member_id WHERE a.id=? LIMIT 1');$stmt->bind_param('i',$mid);$stmt->execute();$member=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$member){unset($_SESSION['perpus_member_id']);$mid=0;}else{$profile=sds_perpus_identity_profile($conn,(string)$member['pemilik_tipe'],(int)($member['pemilik_id']??0),$member);$stmt=$conn->prepare("SELECT pd.*,p.tanggal_pinjam,b.judul,e.barcode,COALESCE((SELECT SUM(dp.nominal) FROM perpus_denda_pembayaran dp WHERE dp.detail_id=pd.id),0) dibayar FROM perpus_peminjaman_detail pd JOIN perpus_peminjaman p ON p.id=pd.peminjaman_id LEFT JOIN perpus_buku b ON b.id=pd.buku_id LEFT JOIN perpus_buku_eksemplar e ON e.id=pd.eksemplar_id WHERE p.anggota_id=? ORDER BY pd.id DESC LIMIT 100");$stmt->bind_param('i',$mid);$stmt->execute();$rr=$stmt->get_result();while($rr&&($x=$rr->fetch_assoc())){if($x['status']==='dipinjam')$loans[]=$x;else$history[]=$x;$fine+=max(0,(float)$x['denda']-(float)$x['dibayar']);}$stmt->close();$stmt=$conn->prepare("SELECT r.*,b.judul,b.isbn,(SELECT COUNT(*) FROM perpus_reservasi q WHERE q.buku_id=r.buku_id AND q.status IN ('menunggu','siap') AND (q.tanggal_reservasi<r.tanggal_reservasi OR (q.tanggal_reservasi=r.tanggal_reservasi AND q.id<=r.id))) posisi FROM perpus_reservasi r JOIN perpus_buku b ON b.id=r.buku_id WHERE r.anggota_id=? ORDER BY r.id DESC LIMIT 50");$stmt->bind_param('i',$mid);$stmt->execute();$rr=$stmt->get_result();while($rr&&($x=$rr->fetch_assoc()))$reservations[]=$x;$stmt->close();$stmt=$conn->prepare('SELECT * FROM perpus_notifikasi WHERE anggota_id=? ORDER BY id DESC LIMIT 50');$stmt->bind_param('i',$mid);$stmt->execute();$rr=$stmt->get_result();while($rr&&($x=$rr->fetch_assoc()))$notifications[]=$x;$stmt->close();}}
?><!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Akun Saya · <?=ah($school['nama_sekolah'])?></title><link rel="stylesheet" href="assets/opac.css?v=2.6.1"><style>.account-wrap{max-width:1050px;margin:40px auto}.account-card{background:#fff;border:1px solid var(--line);border-radius:16px;padding:24px;margin-bottom:18px}.account-login{max-width:520px;margin:auto}.account-login label{display:block;font-weight:700;font-size:13px;margin:14px 0}.account-login input{width:100%;padding:13px;border:1px solid #d6dde8;border-radius:9px;margin-top:6px}.account-login button,.account-action{border:0;background:var(--blue2);color:#fff;padding:12px 16px;border-radius:9px;font-weight:700}.account-alert{padding:12px;border-radius:9px;background:#fee2e2;color:#991b1b;margin-bottom:12px}.account-success{padding:12px;border-radius:9px;background:#dcfce7;color:#166534;margin-bottom:12px}.account-head{display:flex;justify-content:space-between;align-items:start;gap:15px}.account-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:20px 0}.account-stats div{background:#f7f9fc;border:1px solid var(--line);padding:15px;border-radius:12px}.account-stats strong{display:block;font-size:25px}.account-table{width:100%;border-collapse:collapse}.account-table th,.account-table td{padding:11px;border-bottom:1px solid var(--line);text-align:left;font-size:13px}.account-table th{color:var(--muted)}.account-tabs{display:flex;gap:8px;flex-wrap:wrap;margin:20px 0}.account-tabs a{padding:9px 13px;border-radius:9px;background:#eef3fb;color:#244a7c;text-decoration:none}.notice-new{border-left:4px solid #f59e0b}.inline-form{display:inline}.btn-danger-small{border:0;border-radius:7px;padding:7px 10px;background:#fee2e2;color:#991b1b}@media(max-width:700px){.account-stats{grid-template-columns:1fr 1fr}.account-table{display:block;overflow:auto}.account-head{display:block}.account-head a{display:inline-block;margin-top:10px}}</style></head><body><header class="opac-header"><div class="opac-container opac-header-inner"><a class="opac-brand" href="<?=$base?>"><span class="opac-logo">📚</span><span><strong>Akun Saya</strong><small><?=ah($school['nama_sekolah'])?></small></span></a><nav><a href="<?=$base?>">Katalog</a><a href="saran.php">Kritik & Saran</a></nav></div></header><main class="opac-container account-wrap"><?php if(!$member):?><div class="account-card account-login"><h1>Masuk sebagai Anggota</h1><p class="opac-author">Tempelkan Kartu Pelajar Anda</p><?php if($error):?><div class="account-alert"><?=ah($error)?></div><?php endif;?><form method="post" autocomplete="off"><input type="hidden" name="action" value="login"><label>Kartu Pelajar<input name="rfid" required autofocus inputmode="numeric" autocomplete="off" placeholder="Tempelkan kartu pada reader RFID"></label><button>Masuk ke Akun Saya</button></form></div><?php else:?><?php if($message):?><div class="account-success"><?=ah($message)?></div><?php endif;?><?php if($error):?><div class="account-alert"><?=ah($error)?></div><?php endif;?><div class="account-card"><div class="account-head"><div><small><?=ah($member['nomor_anggota'])?> · <?=ah($member['tipe_member']?:'Anggota')?></small><h1><?=ah($profile['nama'])?></h1><p class="opac-author"><?=ah($profile['identitas'])?> · <?=ah($profile['unit'])?></p></div><a href="?logout=1">Keluar</a></div><div class="account-stats"><div><span>Pinjaman Aktif</span><strong><?=count($loans)?></strong></div><div><span>Reservasi Aktif</span><strong><?=count(array_filter($reservations,fn($x)=>in_array($x['status'],['menunggu','siap'],true)))?></strong></div><div><span>Notifikasi Baru</span><strong><?=count(array_filter($notifications,fn($x)=>$x['status']==='baru'))?></strong></div><div><span>Sisa Denda</span><strong>Rp <?=number_format($fine,0,',','.')?></strong></div></div><?php if($requestedBook>0):?><form method="post" class="account-card" style="background:#eff6ff"><input type="hidden" name="csrf" value="<?=ah(member_csrf())?>"><input type="hidden" name="action" value="reserve"><input type="hidden" name="book_id" value="<?=$requestedBook?>"><strong>Konfirmasi reservasi koleksi</strong><p>Tekan tombol berikut untuk menambahkan koleksi ke daftar reservasi/inden Anda.</p><button class="account-action">Konfirmasi Reservasi</button></form><?php endif;?></div>
<div class="account-card"><h2>Reservasi & Inden</h2><div style="overflow:auto"><table class="account-table"><thead><tr><th>Koleksi</th><th>Posisi</th><th>Status</th><th>Batas Ambil</th><th>Aksi</th></tr></thead><tbody><?php if(!$reservations):?><tr><td colspan="5">Belum ada reservasi.</td></tr><?php else:foreach($reservations as $x):?><tr><td><?=ah($x['judul'])?><div><small><?=ah($x['isbn']?:'-')?></small></div></td><td>#<?=(int)$x['posisi']?></td><td><b><?=ah(ucfirst($x['status']))?></b></td><td><?=$x['batas_ambil']?date('d/m/Y H:i',strtotime($x['batas_ambil'])):'-'?></td><td><?php if(in_array($x['status'],['menunggu','siap'],true)):?><form method="post" class="inline-form" onsubmit="return confirm('Batalkan reservasi ini?')"><input type="hidden" name="csrf" value="<?=ah(member_csrf())?>"><input type="hidden" name="action" value="cancel_reservation"><input type="hidden" name="reservation_id" value="<?=(int)$x['id']?>"><button class="btn-danger-small">Batalkan</button></form><?php else:?>-<?php endif;?></td></tr><?php endforeach;endif;?></tbody></table></div></div>
<div class="account-card"><div class="account-head"><h2>Notifikasi</h2><?php if(array_filter($notifications,fn($x)=>$x['status']==='baru')):?><form method="post"><input type="hidden" name="csrf" value="<?=ah(member_csrf())?>"><input type="hidden" name="action" value="read_notifications"><button class="btn-danger-small" style="background:#e0f2fe;color:#075985">Tandai Dibaca</button></form><?php endif;?></div><?php if(!$notifications):?><p>Belum ada notifikasi.</p><?php else:foreach($notifications as $n):?><div class="account-card <?=$n['status']==='baru'?'notice-new':''?>" style="padding:14px"><strong><?=ah($n['judul'])?></strong><p><?=ah($n['pesan'])?></p><small><?=date('d/m/Y H:i',strtotime($n['created_at']))?></small></div><?php endforeach;endif;?></div>
<div class="account-card"><h2>Pinjaman Aktif</h2><div style="overflow:auto"><table class="account-table"><thead><tr><th>Buku</th><th>Barcode</th><th>Pinjam</th><th>Jatuh Tempo</th><th>Status</th></tr></thead><tbody><?php if(!$loans):?><tr><td colspan="5">Tidak ada pinjaman aktif.</td></tr><?php else:foreach($loans as $x):$late=$x['tanggal_jatuh_tempo']&&$x['tanggal_jatuh_tempo']<date('Y-m-d');?><tr><td><?=ah($x['judul']?:'Buku lama')?></td><td><code><?=ah($x['barcode']?:$x['kode_resi'])?></code></td><td><?=ah($x['tanggal_pinjam'])?></td><td><?=ah($x['tanggal_jatuh_tempo'])?></td><td><b style="color:<?=$late?'#b91c1c':'#166534'?>"><?=$late?'Terlambat':'Dipinjam'?></b></td></tr><?php endforeach;endif;?></tbody></table></div></div>
<div class="account-card"><h2>Riwayat Terakhir</h2><div style="overflow:auto"><table class="account-table"><thead><tr><th>Buku</th><th>Tanggal Kembali</th><th>Kondisi</th><th>Denda</th></tr></thead><tbody><?php if(!$history):?><tr><td colspan="4">Belum ada riwayat.</td></tr><?php else:foreach(array_slice($history,0,20) as $x):?><tr><td><?=ah($x['judul']?:'Buku lama')?></td><td><?=ah($x['tanggal_kembali']?:'-')?></td><td><?=ah(ucfirst((string)($x['kondisi_kembali']??$x['status'])))?></td><td>Rp <?=number_format(max(0,(float)$x['denda']-(float)$x['dibayar']),0,',','.')?></td></tr><?php endforeach;endif;?></tbody></table></div></div><?php endif;?></main></body></html>
